use std::collections::HashMap;

impl Solution {
    pub fn clone_graph(node: Option<Box<Node>>) -> Option<Box<Node>> {
        if node.is_none() {
            return None;
        }
        let mut cloned: HashMap<i32, Option<Box<Node>>> = HashMap::new();

        fn dfs(
            node: Option<Box<Node>>,
            cloned: &mut HashMap<i32, Option<Box<Node>>>,
        ) -> Option<Box<Node>> {
            if let Some(n) = node {
                if let Some(existing) = cloned.get(&n.val) {
                    return existing.clone();
                }
                let mut copy = Box::new(Node::new(n.val));
                cloned.insert(n.val, Some(copy.clone()));
                for neighbor in n.neighbors {
                    if let Some(cloned_neighbor) = dfs(neighbor, cloned) {
                        copy.neighbors.push(cloned_neighbor);
                    }
                }
                return Some(copy);
            }
            None
        }

        dfs(node, &mut cloned)
    }
}

