        if grid[r][c] == 2:
            return 0
        grid[r][c] = 2
        return dfs(r + 1, c) + dfs(r - 1, c) + dfs(r, c + 1) + dfs(r, c - 1)

    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 1:
                perimeter = dfs(r, c)
                break
        if perimeter:
            break
    return perimeter

