impl Solution {
    pub fn solve(board: &mut Vec<Vec<char>>) {
        if board.is_empty() {
            return;
        }
        let rows = board.len();
        let cols = board[0].len();

        fn dfs(board: &mut Vec<Vec<char>>, r: i32, c: i32) {
            let rows = board.len() as i32;
            let cols = board[0].len() as i32;
            if r < 0 || r >= rows || c < 0 || c >= cols || board[r as usize][c as usize] != 'O' {
                return;
            }
            board[r as usize][c as usize] = 'S';
            dfs(board, r + 1, c);
            dfs(board, r - 1, c);
            dfs(board, r, c + 1);
            dfs(board, r, c - 1);
        }

        for r in 0..rows {
            dfs(board, r as i32, 0);
            dfs(board, r as i32, (cols - 1) as i32);
        }
        for c in 0..cols {
            dfs(board, 0, c as i32);
            dfs(board, (rows - 1) as i32, c as i32);
        }

        for r in 0..rows {
            for c in 0..cols {
                match board[r][c] {
                    'O' => board[r][c] = 'X',
                    'S' => board[r][c] = 'O',
                    _ => {}
                }
            }
        }
    }
}
